+//! Test utilities for pt-core.
+//!
+//! This module provides test infrastructure including:
+//! - Test logging with timestamps
+//! - Fixture loading helpers
+//! - Common assertions
+//! - Tempdir management
+
+use std::path::{Path, PathBuf};
+use std::time::Instant;
+
+// ============================================================================
+// Macros (must be defined first for use in this module)
+// ============================================================================
+
+/// Log a message to stderr with timestamp (for test output).
+///
+/// This macro writes to stderr so it appears in test output when using
+/// `cargo test -- --nocapture` or when tests fail.
+#[macro_export]
+macro_rules! test_log {
+    ($($arg:tt)*) => {{
+        use std::time::SystemTime;
+        let now = SystemTime::now()
+            .duration_since(SystemTime::UNIX_EPOCH)
+            .unwrap_or_default();
+        let secs = now.as_secs() % 86400; // Time of day
+        let hours = secs / 3600;
+        let mins = (secs % 3600) / 60;
+        let secs = secs % 60;
+        let millis = now.subsec_millis();
+        eprintln!(
+            "[{:02}:{:02}:{:02}.{:03}] {}",
+            hours, mins, secs, millis,
+            format!($($arg)*)
+        );
+    }};
+}
+
+/// Assert that a Result is Ok and return the value.
+#[macro_export]
+macro_rules! assert_ok {
+    ($expr:expr) => {
+        match $expr {
+            Ok(val) => val,
+            Err(e) => panic!("Expected Ok, got Err: {:?}", e),
+        }
+    };
+    ($expr:expr, $msg:expr) => {
+        match $expr {
+            Ok(val) => val,
+            Err(e) => panic!("{}: {:?}", $msg, e),
+        }
+    };
+}
+
+/// Assert that a Result is Err.
+#[macro_export]
+macro_rules! assert_err {
+    ($expr:expr) => {
+        match $expr {
+            Ok(val) => panic!("Expected Err, got Ok: {:?}", val),
+            Err(_) => {}
+        }
+    };
+    ($expr:expr, $msg:expr) => {
+        match $expr {
+            Ok(val) => panic!("{}: got Ok({:?})", $msg, val),
+            Err(_) => {}
+        }
+    };
+}
+
+/// Assert that two floating point numbers are approximately equal.
+#[macro_export]
+macro_rules! assert_approx_eq {
+    ($a:expr, $b:expr) => {
+        $crate::assert_approx_eq!($a, $b, 1e-6_f64)
+    };
+    ($a:expr, $b:expr, $epsilon:expr) => {{
+        let a: f64 = $a;
+        let b: f64 = $b;
+        let eps: f64 = $epsilon;
+        let diff = (a - b).abs();
+        if diff > eps {
+            panic!(
+                "assertion failed: `(left ~= right)` (left: `{}`, right: `{}`, diff: `{}`, epsilon: `{}`)",
+                a, b, diff, eps
+            );
+        }
+    }};
+}
